import type * as DMMF from '@prisma/dmmf'

const scalarTypeMap: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'number',
  Boolean: 'boolean',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Uint8Array',
}

/**
 * Maps a Prisma DMMF scalar/enum field to its TypeScript type string.
 * Enum types pass through unchanged; scalar types are mapped to their JS primitives.
 */
export function dmmfToTsType(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return field.type
  }
  return scalarTypeMap[field.type] ?? 'unknown'
}

