import fs from 'node:fs/promises'
import os from 'node:os'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { generateRestClient } from '../generate-rest-client'

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  fields: [
    makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String', isRequired: false }),
    makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
  ],
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
}

const mockDmmf: DMMF.Document = {
  datamodel: {
    models: [userModel],
    enums: [],
    types: [],
    indexes: [],
  },
  schema: {
    inputObjectTypes: {},
    outputObjectTypes: { model: [], prisma: [] },
    enumTypes: { prisma: [] },
    fieldRefTypes: {},
  },
  mappings: {
    modelOperations: [{ model: 'User', plural: 'users' }],
    otherOperations: { read: [], write: [] },
  },
}

function makeOptions(outputDir: string): GeneratorOptions {
  return {
    generator: {
      name: 'rest-client',
      provider: { fromEnvVar: null, value: 'prisma-rest-client' },
      output: { fromEnvVar: null, value: outputDir },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/fake/schema.prisma',
    },
    otherGenerators: [],
    schemaPath: '/fake/schema.prisma',
    dmmf: mockDmmf,
    datasources: [],
    datamodel: '',
    version: '0.0.0',
  }
}

describe('generateRestClient', () => {
  let outputDir: string

  beforeEach(async () => {
    outputDir = await fs.mkdtemp(path.join(os.tmpdir(), 'rest-client-gen-test-'))
  })

  afterEach(async () => {
    await fs.rm(outputDir, { recursive: true, force: true })
  })

  test('generates a TypeScript interface for each model', async () => {
    await generateRestClient(makeOptions(outputDir))

    const content = await fs.readFile(path.join(outputDir, 'user.ts'), 'utf-8')

    expect(content).toContain('export interface User {')
    expect(content).toContain('id: number')
    expect(content).toContain('email: string')
    expect(content).toContain('name?: string')
    expect(content).toContain('createdAt: Date')
  })

  test('generates a WhereUnique type from id and unique fields', async () => {
    await generateRestClient(makeOptions(outputDir))

    const content = await fs.readFile(path.join(outputDir, 'user.ts'), 'utf-8')

    expect(content).toContain('export type UserWhereUnique =')
    expect(content).toContain('| { id: number }')
    expect(content).toContain('| { email: string }')
  })

  test('generates all five CRUD methods on the RestClient class', async () => {
    await generateRestClient(makeOptions(outputDir))

    const content = await fs.readFile(path.join(outputDir, 'user.ts'), 'utf-8')

    expect(content).toContain('async findMany(')
    expect(content).toContain('async findUnique(')
    expect(content).toContain('async create(')
    expect(content).toContain('async update(')
    expect(content).toContain('async delete(')
  })

  test('generates an index.ts that re-exports models and PrismaRestClient', async () => {
    await generateRestClient(makeOptions(outputDir))

    const content = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')

    expect(content).toContain("export * from './user'")
    expect(content).toContain("export { PrismaRestClient } from './prisma-rest-client'")
  })

  test('generates a PrismaRestClient factory with a getter per model using plural name', async () => {
    await generateRestClient(makeOptions(outputDir))

    const content = await fs.readFile(path.join(outputDir, 'prisma-rest-client.ts'), 'utf-8')

    expect(content).toContain('export class PrismaRestClient {')
    expect(content).toContain('get users(): UserRestClient {')
  })
})

